using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    SummarizeResponse Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "is", "are", "was", "were", "be", "been", "being",
        "have", "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "need", "dare", "ought",
        "used", "to", "of", "in", "for", "on", "with", "at", "by", "from",
        "as", "into", "through", "during", "before", "after", "above", "below",
        "between", "out", "off", "over", "under", "again", "further", "then",
        "once", "and", "but", "or", "nor", "not", "so", "yet", "both", "either",
        "neither", "each", "every", "all", "any", "few", "more", "most", "other",
        "some", "such", "no", "only", "own", "same", "than", "too", "very",
        "just", "because", "if", "when", "where", "how", "what", "which", "who",
        "whom", "this", "that", "these", "those", "i", "me", "my", "myself",
        "we", "our", "ours", "ourselves", "you", "your", "yours", "yourself",
        "he", "him", "his", "himself", "she", "her", "hers", "herself",
        "it", "its", "itself", "they", "them", "their", "theirs", "themselves"
    };

    public SummarizeResponse Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count == 0)
        {
            return new SummarizeResponse
            {
                Summary = string.Empty,
                OriginalSentenceCount = 0,
                SummarySentenceCount = 0
            };
        }

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        // Select top-scored sentences, preserving original order
        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .OrderBy(i => i)
            .ToList();

        var summarySentences = topIndices.Select(i => sentences[i]);

        return new SummarizeResponse
        {
            Summary = string.Join(" ", summarySentences),
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = maxSentences
        };
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var wordCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                wordCounts.TryGetValue(word, out int count);
                wordCounts[word] = count + 1;
            }
        }

        if (wordCounts.Count == 0)
            return new Dictionary<string, double>();

        var maxFreq = wordCounts.Values.Max();
        return wordCounts.ToDictionary(
            kvp => kvp.Key,
            kvp => (double)kvp.Value / maxFreq,
            StringComparer.OrdinalIgnoreCase);
    }

    private static List<double> ScoreSentences(List<string> sentences, Dictionary<string, double> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = ExtractWords(sentence);
            double score = 0;
            int scoredWords = 0;

            foreach (var word in words)
            {
                if (wordFrequencies.TryGetValue(word, out double freq))
                {
                    score += freq;
                    scoredWords++;
                }
            }

            // Normalize by word count to avoid bias toward long sentences
            scores.Add(scoredWords > 0 ? score / scoredWords : 0);
        }

        return scores;
    }

    private static IEnumerable<string> ExtractWords(string text)
    {
        return WordExtractor().Matches(text).Select(m => m.Value);
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordExtractor();
}

using Microsoft.AspNetCore.Mvc;
using DocSummary.Models;
using DocSummary.Services;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummarizeController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var result = _summaryService.Summarize(request.DocumentText, request.MaxSentences);
        return Ok(result);
    }
}

